import clsx from 'clsx';
import { type ComponentProps, type ElementType, forwardRef } from 'react';

import Spacings from '@dynatrace/strato-design-tokens/spacings';

import * as styles from './InteractiveChartTooltip.sty.js';
import { Flex, FlexProps } from '../../../../../../layouts/flex/Flex.js';

export const TOOLTIP_MAX_HEIGHT = 200; //in px
const TOOLTIP_MAX_WIDTH = 300; //in px
export const DEFAULT_TOOLTIP_MIN_WIDTH = '225px';

/**
 * @internal
 */
export function StyledChartTooltipHeader(props: ComponentProps<'div'>) {
  const { className, ...remainingProps } = props;
  return (
    <div
      {...remainingProps}
      className={clsx(styles.tooltipHeader, className)}
      tabIndex={-1}
    />
  );
}

/**
 * @internal
 */
export function StyledTitleContainer<E extends ElementType = 'div'>(
  props: FlexProps<E>,
) {
  const { className, as = 'div' as E, ...remainingProps } = props;
  return (
    <Flex
      {...remainingProps}
      as={as satisfies ElementType}
      padding={4}
      className={clsx(styles.titleContainer, className)}
    />
  );
}

export function StyledTooltipContainer(
  props: ComponentProps<'div'> & {
    minWidth: number | string;
    // needed to prevent tooltip blinking bug
    allowPointerEvents: boolean | undefined;
  },
) {
  const { style, minWidth, allowPointerEvents, ...remainingProps } = props;
  return (
    <div
      {...remainingProps}
      style={{
        ...style,
        minWidth,
        maxWidth: `calc(${TOOLTIP_MAX_WIDTH}px - (${Spacings.Size8} * 2))`,
        pointerEvents: allowPointerEvents ? 'auto' : 'none',
        cursor: allowPointerEvents ? 'pointer' : 'auto',
      }}
    />
  );
}

export function StyledFormattedTimeframe(props: ComponentProps<'span'>) {
  const { className, ...remainingProps } = props;
  return (
    <span
      {...remainingProps}
      className={clsx(styles.formattedTimeframe, className)}
    />
  );
}

export const TooltipItemsContainer = forwardRef<
  HTMLDivElement,
  ComponentProps<'div'>
>((props, ref) => {
  const { className, ...remainingProps } = props;
  return (
    <div
      ref={ref}
      {...remainingProps}
      className={clsx(styles.tooltipItemsContainer, className)}
    />
  );
});

export const ScrollableContainerParent = forwardRef<
  HTMLDivElement,
  ComponentProps<'div'>
>((props, ref) => {
  const { className, style, ...remainingProps } = props;
  return (
    <div
      ref={ref}
      {...remainingProps}
      className={clsx(styles.scrollableContainerParent, className)}
      style={{ ...(style ?? {}), maxHeight: TOOLTIP_MAX_HEIGHT }}
    />
  );
});

export const TooltipItems = forwardRef<HTMLDivElement, ComponentProps<'div'>>(
  (props, ref) => {
    const { className, ...remainingProps } = props;
    return (
      <div
        ref={ref}
        {...remainingProps}
        className={clsx(styles.tooltipItem, className)}
      />
    );
  },
);
